/**
 * font-manager.ts — Engine de gerenciamento de tipografia avançada
 *
 * Gerencia Google Fonts com lazy loading, text effects (shadow, outline, gradient),
 * presets de estilo e conversão CSS-in-JS. Todas as funções são puras e exportadas
 * individualmente para facilitar testes.
 */

// ─── Types ─────────────────────────────────────────────────────────

export type FontWeight = 100 | 200 | 300 | 400 | 500 | 600 | 700 | 800 | 900;

export type FontStyleValue = 'normal' | 'italic';

export type GradientDirection = 'horizontal' | 'vertical' | 'diagonal';

export type TextEffectType = 'shadow' | 'outline' | 'gradient';

export type TextPresetName = 'titulo' | 'subtitulo' | 'corpo' | 'callout' | 'codigo';

export interface FontFamily {
  family: string;
  weights: FontWeight[];
  category: 'sans-serif' | 'serif' | 'monospace' | 'display' | 'handwriting';
}

export interface FontConfig {
  family: string;
  weight: FontWeight;
  style: FontStyleValue;
  size: number;
  lineHeight?: number;
  letterSpacing?: number;
  color?: string;
}

export interface TextShadowEffect {
  type: 'shadow';
  offsetX: number;
  offsetY: number;
  blur: number;
  color: string;
}

export interface TextOutlineEffect {
  type: 'outline';
  width: number;
  color: string;
}

export interface TextGradientEffect {
  type: 'gradient';
  startColor: string;
  endColor: string;
  direction: GradientDirection;
}

export type TextEffect = TextShadowEffect | TextOutlineEffect | TextGradientEffect;

export interface TextStylePreset {
  name: TextPresetName;
  label: string;
  config: FontConfig;
  effects: TextEffect[];
}

