// ─── Google Fonts URL Builder ──────────────────────────────────────

/**
 * Codifica o nome da família para uso na URL do Google Fonts.
 * Substitui espaços por '+'.
 */
export function encodeFontFamily(family: string): string {
  return family.replace(/\s+/g, '+');
}

/**
 * Constrói a URL do Google Fonts CSS API v2 para uma ou mais famílias.
 *
 * @example
 * buildGoogleFontsUrl([{ family: 'Roboto', weights: [400, 700] }])
 * // → 'https://fonts.googleapis.com/css2?family=Roboto:wght@400;700&display=swap'
 */
export function buildGoogleFontsUrl(
  families: ReadonlyArray<{ family: string; weights?: ReadonlyArray<FontWeight> }>,
): string {
  if (families.length === 0) {
    return '';
  }

  const params = families.map((f) => {
    const encoded = encodeFontFamily(f.family);
    if (f.weights && f.weights.length > 0) {
      const sorted = [...f.weights].sort((a, b) => a - b);
      return `family=${encoded}:wght@${sorted.join(';')}`;
    }
    return `family=${encoded}`;
  });

  return `https://fonts.googleapis.com/css2?${params.join('&')}&display=swap`;
}

// ─── Font Loading ──────────────────────────────────────────────────

const loadedFonts = new Set<string>();

/**
 * Injeta a tag <link> do Google Fonts no DOM para carregar uma fonte.
 * Retorna true se a tag foi criada, false se já estava carregada.
 *
 * Apenas funciona no browser (verifica `typeof document`).
 */
export function loadGoogleFont(
  family: string,
  weights?: ReadonlyArray<FontWeight>,
): boolean {
  if (typeof document === 'undefined') {
    return false;
  }

  const key = `${family}:${(weights ?? [400]).join(',')}`;
  if (loadedFonts.has(key)) {
    return false;
  }

  const url = buildGoogleFontsUrl([{ family, weights }]);
  const link = document.createElement('link');
  link.rel = 'stylesheet';
  link.href = url;
  link.dataset.fontFamily = family;
  document.head.appendChild(link);
  loadedFonts.add(key);

  return true;
}

/**
 * Verifica se uma fonte está carregada no browser usando a Font Loading API.
 */
export function isFontLoaded(family: string, weight: FontWeight = 400): boolean {
  if (typeof document === 'undefined') {
    return false;
  }
  try {
    return document.fonts.check(`${weight} 16px "${family}"`);
  } catch {
    return false;
  }
}

/**
 * Reseta o tracker de fontes carregadas (para testes).
 */
export function resetLoadedFonts(): void {
  loadedFonts.clear();
}

// ─── Text Effects Engine ───────────────────────────────────────────

/**
 * Gera CSS properties para text-shadow.
 */
export function applyTextShadow(effect: TextShadowEffect): Record<string, string> {
  return {
    textShadow: `${effect.offsetX}px ${effect.offsetY}px ${effect.blur}px ${effect.color}`,
  };
}

/**
 * Gera CSS properties para outline de texto via text-stroke + paint-order.
 */
export function applyTextOutline(effect: TextOutlineEffect): Record<string, string> {
  return {
    WebkitTextStroke: `${effect.width}px ${effect.color}`,
    paintOrder: 'stroke fill',
  };
}

/**
 * Converte GradientDirection para graus CSS.
 */
export function gradientDirectionToDeg(direction: GradientDirection): string {
  switch (direction) {
    case 'horizontal':
      return '90deg';
    case 'vertical':
      return '180deg';
    case 'diagonal':
      return '135deg';
  }
}

/**
 * Gera CSS properties para gradient fill de texto.
 */
export function applyTextGradient(effect: TextGradientEffect): Record<string, string> {
  const deg = gradientDirectionToDeg(effect.direction);
  return {
    backgroundImage: `linear-gradient(${deg}, ${effect.startColor}, ${effect.endColor})`,
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    backgroundClip: 'text',
  };
}

/**
 * Aplica um TextEffect retornando as CSS properties correspondentes.
 */
export function applyTextEffect(effect: TextEffect): Record<string, string> {
  switch (effect.type) {
    case 'shadow':
      return applyTextShadow(effect);
    case 'outline':
      return applyTextOutline(effect);
    case 'gradient':
      return applyTextGradient(effect);
  }
}

/**
 * Aplica múltiplos effects e mescla em um único style object.
 * Effects posteriores sobrescrevem propriedades duplicadas.
 */
export function mergeTextEffects(effects: ReadonlyArray<TextEffect>): Record<string, string> {
  const result: Record<string, string> = {};
  for (const effect of effects) {
    const props = applyTextEffect(effect);
    Object.assign(result, props);
  }
  return result;
}

