// ─── CSS-in-JS Helper ──────────────────────────────────────────────

/**
 * Converte FontConfig + effects em um style object pronto para uso em React.
 */
export function textStyleToCSS(
  config: FontConfig,
  effects: ReadonlyArray<TextEffect> = [],
): Record<string, string | number> {
  const base: Record<string, string | number> = {
    fontFamily: `"${config.family}", ${getFallbackStack(config.family)}`,
    fontWeight: config.weight,
    fontStyle: config.style,
    fontSize: `${config.size}px`,
  };

  if (config.lineHeight !== undefined) {
    base.lineHeight = config.lineHeight;
  }
  if (config.letterSpacing !== undefined) {
    base.letterSpacing = `${config.letterSpacing}px`;
  }
  if (config.color) {
    base.color = config.color;
  }

  if (effects.length > 0) {
    const effectStyles = mergeTextEffects(effects);
    Object.assign(base, effectStyles);
  }

  return base;
}

/**
 * Retorna o fallback CSS stack baseado na categoria da fonte.
 */
export function getFallbackStack(family: string): string {
  const font = POPULAR_FONTS.find((f) => f.family === family);
  if (!font) {
    return 'sans-serif';
  }
  switch (font.category) {
    case 'serif':
      return 'Georgia, "Times New Roman", serif';
    case 'monospace':
      return '"Courier New", Courier, monospace';
    case 'display':
      return 'Impact, "Arial Black", sans-serif';
    case 'handwriting':
      return '"Comic Sans MS", cursive';
    case 'sans-serif':
    default:
      return 'Arial, Helvetica, sans-serif';
  }
}

// ─── Validation Helpers ────────────────────────────────────────────

const VALID_WEIGHTS: ReadonlyArray<FontWeight> = [100, 200, 300, 400, 500, 600, 700, 800, 900];

/**
 * Valida se um FontConfig é válido.
 */
export function isValidFontConfig(config: unknown): config is FontConfig {
  if (typeof config !== 'object' || config === null) {
    return false;
  }

  const c = config as Record<string, unknown>;

  if (typeof c.family !== 'string' || c.family.trim().length === 0) {
    return false;
  }
  if (typeof c.weight !== 'number' || !VALID_WEIGHTS.includes(c.weight as FontWeight)) {
    return false;
  }
  if (c.style !== 'normal' && c.style !== 'italic') {
    return false;
  }
  if (typeof c.size !== 'number' || c.size <= 0) {
    return false;
  }
  if (c.lineHeight !== undefined && (typeof c.lineHeight !== 'number' || c.lineHeight <= 0)) {
    return false;
  }
  if (c.letterSpacing !== undefined && typeof c.letterSpacing !== 'number') {
    return false;
  }
  if (c.color !== undefined && typeof c.color !== 'string') {
    return false;
  }

  return true;
}

/**
 * Filtra fontes por categoria.
 */
export function filterFontsByCategory(
  category: FontFamily['category'],
): ReadonlyArray<FontFamily> {
  return POPULAR_FONTS.filter((f) => f.category === category);
}

/**
 * Busca fontes pelo nome (case-insensitive, partial match).
 */
export function searchFonts(query: string): ReadonlyArray<FontFamily> {
  const lower = query.toLowerCase().trim();
  if (lower.length === 0) {
    return POPULAR_FONTS;
  }
  return POPULAR_FONTS.filter((f) => f.family.toLowerCase().includes(lower));
}
